  condition: "NM" | "LP" | "MP" | "HP" | "DMG"
  language?: string
  finish?: string
  price: number
  quantity?: number
  title: string
  description?: string
  images?: string[]
  shipping_method?: "standard" | "priority" | "free_over_25"
